mapper.select:
SELECT * FROM (
	SELECT ROWNUM RN, A.* FROM (
		SELECT
			MEMBER_ID AS memberId,
			NICKNAME AS nickname,
			EMAIL AS email,
			JOIN_DATE AS joinDate,
			STATUS AS status,
			ROLE AS role
		FROM MEMBER
		WHERE 1=1

			AND (
				MEMBER_ID LIKE '%' || #{keyword} || '%'
				OR NICKNAME LIKE '%' || #{keyword} || '%'
				OR EMAIL LIKE '%' || #{keyword} || '%'
			)


			AND STATUS = #{status}


	AND ROLE = #{role}


		ORDER BY JOIN_DATE DESC, MEMBER_ID DESC
	) A
	WHERE ROWNUM <= #{endRow}
)
WHERE RN >= #{startRow}

SELECT COUNT(*)
FROM MEMBER
WHERE 1=1


	AND (
		MEMBER_ID LIKE '%' || #{keyword} || '%'
		OR NICKNAME LIKE '%' || #{keyword} || '%'
		OR EMAIL LIKE '%' || #{keyword} || '%'
	)



	AND STATUS = #{status}



	AND ROLE = #{role}

SELECT * FROM ( SELECT ROWNUM AS RN, T.* FROM ( SELECT A.ANIMAL_ID AS animalId, A.ANIMAL_NAME AS animalName, A.ANIMAL_TYPE AS animalType, A.BREED AS breed, A.GENDER AS gender, A.AGE AS age, A.WEIGHT AS weight, A.ADOPTION_STATUS AS adoptionStatus, A.PERSONALITY AS personality, A.VIEW_COUNT AS viewCount, A.CREATE_DATE AS createDate,
I.SAVE_FILE_NAME AS mainImage FROM ANIMAL A
LEFT OUTER JOIN ANIMAL_IMAGE I ON A.ANIMAL_ID = I.ANIMAL_ID AND I.IS_MAIN = 'Y' WHERE 1=1
ORDER BY A.VIEW_COUNT DESC ORDER BY A.CREATE_DATE DESC
) T WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}

SELECT COUNT(*) AS TOTAL_COUNT, COUNT(CASE WHEN ANIMAL_TYPE = 'DOG' THEN 1 END) AS DOG_COUNT, COUNT(CASE WHEN ANIMAL_TYPE = 'CAT' THEN 1 END) AS CAT_COUNT, COUNT(CASE WHEN CREATE_DATE >= TRUNC(SYSDATE, 'IW') THEN 1 END) AS WEEK_NEW_COUNT, COUNT(CASE WHEN ADOPTION_STATUS = '입양가능' THEN 1 END) AS AVAILABLE_COUNT, COUNT(CASE WHEN ADOPTION_STATUS = '입양검토중' THEN 1 END) AS PROGRESS_COUNT,
/* 서브쿼리를 MAX()로 감싸서 그룹 함수로 인식하게 만듭니다 */ MAX((SELECT COUNT(*) FROM ADOPTION WHERE STATUS = '승인' AND TO_CHAR(APPLY_DATE, 'YYYYMM') = TO_CHAR(SYSDATE, 'YYYYMM') )) AS MONTH_DONE_COUNT,
MAX((SELECT COUNT(*) FROM ADOPTION WHERE STATUS = '승인' AND TO_CHAR(APPLY_DATE, 'YYYYMM') = TO_CHAR(ADD_MONTHS(SYSDATE,-1), 'YYYYMM') )) AS LAST_MONTH_DONE_COUNT FROM ANIMAL

/* CDATA 시작: 이 안의 기호들은 안전하게 보호됩니다 */
SELECT * FROM ( /* ── 입양 상담 방문 ── */ SELECT 'ADOPTION' AS TYPE, TO_CHAR(A.ADOPTION_ID) AS ID, A.MEMBER_ID || '님 입양 상담' AS TITLE, NVL(AN.ANIMAL_NAME, '동물') || ' (' || NVL(AN.ANIMAL_TYPE, '-') || ')' AS CONTENT, TO_CHAR(A.VISIT_DATE, 'HH24:MI') AS TIME, TO_CHAR(A.VISIT_DATE, 'YYYY-MM-DD HH24:MI') AS FULL_TIME, TO_CHAR(A.VISIT_DATE, 'YYYY-MM-DD') AS DATE_KEY, A.VISIT_DATE AS SORT_DATE FROM ADOPTION A LEFT JOIN ANIMAL AN ON A.ANIMAL_ID = AN.ANIMAL_ID WHERE A.VISIT_DATE IS NOT NULL AND A.STATUS = '승인' AND A.VISIT_DATE >= TRUNC(SYSDATE, 'IW') AND A.VISIT_DATE < TRUNC(SYSDATE, 'IW') + 7
UNION ALL
/* ── 봉사 활동 ── */ SELECT 'VOLUNTEER' AS TYPE, TO_CHAR(VA.VOLUNTEER_ID) AS ID, VA.MEMBER_ID || '님 봉사' AS TITLE, NVL(VR.TITLE, '봉사') || ' @ ' || NVL(VR.LOCATION, '-') AS CONTENT, TO_CHAR(VA.VOLUNTEER_DATE, 'HH24:MI') AS TIME, TO_CHAR(VA.VOLUNTEER_DATE, 'YYYY-MM-DD HH24:MI') AS FULL_TIME, TO_CHAR(VA.VOLUNTEER_DATE, 'YYYY-MM-DD') AS DATE_KEY, VA.VOLUNTEER_DATE AS SORT_DATE FROM VOLUNTEER_APPLY VA LEFT JOIN VOLUNTEER_RECRUIT VR ON VA.RECRUIT_ID = VR.RECRUIT_ID WHERE VA.VOLUNTEER_DATE IS NOT NULL AND VA.STATUS = '승인' AND VA.VOLUNTEER_DATE >= TRUNC(SYSDATE, 'IW') AND VA.VOLUNTEER_DATE < TRUNC(SYSDATE, 'IW') + 7 ) ORDER BY SORT_DATE ASC
/* CDATA 끝 */

SELECT * FROM ( /* ── 입양 신청: 심사중 상태만 표시 (승인/반려 완료 제외) ── */ SELECT 'ADOPTION' AS TYPE, TO_CHAR(ADOPTION_ID) AS ID, MEMBER_ID || '님이 입양 신청을 하였습니다.' AS TITLE, TO_CHAR(APPLY_DATE, 'YYYY-MM-DD HH24:MI') AS REG_DATE FROM ADOPTION WHERE STATUS = '심사중' /* ← 완료/반려된 건 제외 */
UNION ALL
/* ── 구조 제보: ANIMAL_REPORT 테이블 (미처리만) ── */ SELECT 'RESCUE' AS TYPE, TO_CHAR(REPORT_ID) AS ID, NVL(MEMBER_ID, '비회원') || '님이 유기동물을 제보하였습니다.' AS TITLE, TO_CHAR(REPORT_DATE, 'YYYY-MM-DD HH24:MI') AS REG_DATE FROM ANIMAL_REPORT WHERE PROCESS_YN = 'N' /* 미처리만 표시 */
UNION ALL
/* ── 봉사 신청: 대기 상태만 표시 (승인/반려 완료 제외) ── */ SELECT 'VOLUNTEER' AS TYPE, TO_CHAR(RECRUIT_ID) || '_' || TO_CHAR(VOLUNTEER_ID) AS ID, MEMBER_ID || '님이 봉사 신청을 하였습니다.' AS TITLE, TO_CHAR(APPLY_DATE, 'YYYY-MM-DD HH24:MI') AS REG_DATE FROM VOLUNTEER_APPLY WHERE STATUS = '대기' /* ← 승인/반려 완료 제외 */
UNION ALL
/* ── 후원: 전체 표시 (완료 개념 없음) ── */ SELECT 'DONATION' AS TYPE, TO_CHAR(DONATION_ID) AS ID, DONATOR_NAME || '님이 ' || TO_CHAR(DONATION_AMOUNT, 'FM999,999,999') || '원을 후원하였습니다.' AS TITLE, TO_CHAR(DONATION_DATE, 'YYYY-MM-DD HH24:MI') AS REG_DATE FROM DONATION ) ORDER BY REG_DATE DESC FETCH FIRST 50 ROWS ONLY

