SELECT * FROM ( SELECT ROWNUM AS RN, T.* FROM ( SELECT B.BOARD_ID AS boardId, B.MEMBER_ID AS memberId, B.BOARD_TYPE AS boardType, B.TITLE AS title, B.VIEW_COUNT AS viewCount, B.LIKE_COUNT AS likeCount, B.IS_HIDDEN AS isHidden, TO_CHAR(B.CREATE_DATE, 'YYYY.MM.DD') AS createDate, (SELECT COUNT(*) FROM BOARD_REPORT R WHERE R.BOARD_ID = B.BOARD_ID) AS reportCount FROM BOARD B WHERE 1=1
AND B.BOARD_TYPE = #{boardType}
AND (B.TITLE LIKE '%' || #{keyword} || '%' OR B.MEMBER_ID LIKE '%' || #{keyword} || '%')
ORDER BY B.BOARD_ID DESC ) T WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}

SELECT COUNT(*) FROM BOARD B WHERE 1=1
AND B.BOARD_TYPE = #{boardType}
AND (B.TITLE LIKE '%' || #{keyword} || '%' OR B.MEMBER_ID LIKE '%' || #{keyword} || '%')

mapper.update:
UPDATE BOARD
SET IS_HIDDEN = #{isHidden}
WHERE BOARD_ID = #{boardId}

UPDATE BOARD_REPORT
SET STATUS = #{status}
WHERE BOARD_ID = #{boardId}

