SELECT * FROM ( SELECT ROWNUM AS RN, T.* FROM ( SELECT A.ADOPTION_ID AS adoptionId, A.MEMBER_ID AS memberId, A.ANIMAL_ID AS animalId, A.VISIT_DATE AS visitDate, A.APPLY_DATE AS applyDate, A.STATUS AS status, A.REJECT_REASON AS rejectReason, AN.ANIMAL_NAME AS animalName, AN.ANIMAL_TYPE AS animalType, AN.BREED AS breed, AN.AGE AS age, AN.PERSONALITY AS personality, AI.SAVE_FILE_NAME AS mainImage, M.PROFILE_IMG AS profileImg, D.JOB AS job, D.HOUSING_TYPE AS housingType, D.PET_EXPERIENCE AS petExperience, D.ADDRESS AS address, D.ADOPTION_REASON AS adoptionReason FROM ADOPTION A LEFT JOIN ANIMAL AN ON A.ANIMAL_ID = AN.ANIMAL_ID LEFT JOIN ANIMAL_IMAGE AI ON AN.ANIMAL_ID = AI.ANIMAL_ID AND AI.IS_MAIN = 'Y' LEFT JOIN MEMBER M ON A.MEMBER_ID = M.MEMBER_ID LEFT JOIN ADOPTION_DETAIL D ON A.ADOPTION_ID = D.ADOPTION_ID
A.STATUS = #{statusFilter}
ORDER BY A.APPLY_DATE DESC ) T WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}
